// Filtra contactos donde el email fue enviado hace 3+ dias y tienen menos de 2 follow-ups
var DIAS_ESPERA = parseInt($vars.FOLLOWUP_DIAS_ESPERA || '3');
var MS_ESPERA   = DIAS_ESPERA * 24 * 60 * 60 * 1000;
var ahora       = Date.now();

return $input.all().filter(function(item) {
  var email      = (item.json.Email || '').trim();
  var followupN  = parseInt(item.json.Followup_Num || '0');
  var fechaEmail = item.json.Fecha_Email
    ? new Date(item.json.Fecha_Email).getTime()
    : 0;

  return email.indexOf('@') > -1
    && followupN < 2
    && fechaEmail > 0
    && (ahora - fechaEmail) >= MS_ESPERA;
});

// Construye el email de follow-up (1er o 2do seguimiento)
const n      = $json.Nombre || 'Cliente';
const s      = $json.Estado || '';
const emp    = $vars.EMPRESA_NOMBRE  || 'Nuestra Empresa';
const web    = $vars.WEBSITE_URL     || '#';
const wa     = $vars.WHATSAPP_LINK   || '#';
const emailC = $vars.EMAIL_CONTACTO  || '';
const fNum   = parseInt($json.Followup_Num || '0') + 1;

// Helper: boton CTA
const btn = (url, txt) =>
  `<a href="${url}" style="display:inline-block;background:#1e40af;color:#fff;padding:12px 24px;text-decoration:none;border-radius:5px;font-weight:bold;margin:10px 0">${txt}</a>`;

// Helper: wrapper completo del email
const wrap = (title, accentColor, body) =>
  `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>` +
  `<body style="font-family:Arial,sans-serif;margin:0;padding:0;background:#f5f5f5">` +
  `<div style="max-width:600px;margin:0 auto;background:#ffffff">` +
  `<div style="background:${accentColor};color:#ffffff;padding:28px 32px">` +
  `<h1 style="margin:0;font-size:20px;font-weight:700">${title}</h1></div>` +
  `<div style="padding:28px 32px;color:#333333;line-height:1.7">${body}</div>` +
  `<div style="background:#f4f4f4;padding:16px 32px;text-align:center;font-size:11px;color:#888888">` +
  `<p style="margin:0">${emailC} &nbsp;|&nbsp; Responde BAJA para cancelar suscripcion</p>` +
  `</div></div></body></html>`;

let subj, html;

if (fNum === 1) {
  // PRIMER FOLLOW-UP: tono amigable, recordatorio
  subj = `${n}, quisimos saber si recibiste nuestra propuesta`;

  let contexto = '';
  if (s === 'Interesado') {
    contexto = '<p>Hace unos dias te enviamos informacion sobre nuestra propuesta porque nos dijiste que te interesaba. Queremos asegurarnos de que hayas podido verla.</p>';
  } else if (s === 'No Contesta' || s === 'Buzon de Voz') {
    contexto = '<p>Intentamos contactarte por telefono y luego te enviamos un email. Queremos asegurarnos de que hayas recibido nuestra propuesta.</p>';
  } else {
    contexto = '<p>Hace unos dias te enviamos informacion de nuestra parte. Queremos verificar que hayas podido verla.';
  }

  html = wrap(
    'Seguimiento de tu consulta',
    '#1e40af',
    `<p>Hola <strong>${n}</strong>,</p>` +
    contexto +
    `<div style="background:#eff6ff;border-left:4px solid #1e40af;padding:12px 16px;margin:15px 0;border-radius:0 5px 5px 0">` +
    `<strong>Podemos ayudarte por estos medios:</strong>` +
    `<ul style="margin:8px 0;padding-left:20px">` +
    `<li>Respondiendo este email directamente</li>` +
    `<li>Por WhatsApp: ${btn(wa, 'Escribirnos')}</li>` +
    `<li>Visitando nuestra web: ${btn(web, 'Ver Propuesta')}</li>` +
    `</ul></div>` +
    `<p>Estamos disponibles para resolver cualquier duda.</p>` +
    `<p>Saludos,<br><strong>${emp}</strong></p>`
  );

} else {
  // SEGUNDO FOLLOW-UP: tono respetuoso, ultimo contacto
  subj = `${n}, ultimo mensaje de nuestra parte`;

  html = wrap(
    'Ultimo intento de contacto',
    '#374151',
    `<p>Hola <strong>${n}</strong>,</p>` +
    `<p>Este es nuestro ultimo mensaje para no ser invasivos ni quitarte tiempo.</p>` +
    `<p>Si en algun momento en el futuro necesitas nuestros servicios o quieres conocer nuestra propuesta, aqui estamos. Sera un placer atenderte.</p>` +
    btn(wa, 'Contactarnos cuando lo necesites') +
    `<p style="font-size:13px;color:#666;margin-top:20px">` +
    `Si no quieres recibir mas emails, simplemente responde con la palabra BAJA y te damos de baja inmediatamente.</p>` +
    `<p>Muchas gracias por tu tiempo.<br>Saludos,<br><strong>${emp}</strong></p>`
  );
}

return [{ json: Object.assign({}, $json, {
  subject: subj,
  html: html,
  template_usado: 'followup_' + fNum,
  timestamp_email: new Date().toISOString(),
  Followup_Num: fNum
}) }];
